import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';

const loginSchema = z.object({
  username: z.string().min(1, 'El nombre de usuario es requerido'),
  password: z.string().min(6, 'La contraseña debe tener al menos 6 caracteres'),
});

type LoginFormData = z.infer<typeof loginSchema>;

const Login: React.FC = () => {
  const [isLoading, setIsLoading] = React.useState(false);
  const [error, setError] = React.useState<string>('');

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<LoginFormData>({
    resolver: zodResolver(loginSchema),
  });

  const onSubmit = async (data: LoginFormData) => {
    try {
      setIsLoading(true);
      setError('');
      
      // Aquí irá la lógica de login cuando conectes con el backend
      console.log('Datos del formulario:', data);
      
      // Simular delay
      await new Promise(resolve => setTimeout(resolve, 1000));
      
      // Por ahora solo mostramos los datos en consola
      console.log('Login exitoso:', data);
      
    } catch (err) {
      setError('Error al iniciar sesión. Verifica tus credenciales.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Encabezado */}
      <div className="text-center py-8 bg-white shadow-sm">
        <h1 className="text-4xl font-bold font-tektur text-gray-800">
          <span className="text-primary-600">360</span>
          <span>Sueldos</span>
        </h1>
      </div>

      {/* Contenedor del formulario */}
      <div className="max-w-md mx-auto mt-16 px-4">
        <form 
          onSubmit={handleSubmit(onSubmit)}
          className="bg-white rounded-lg shadow-lg p-8 flex flex-col items-center"
        >
          <h2 className="text-2xl font-semibold font-tektur text-gray-800 mb-8">
            Iniciar Sesión
          </h2>

          {error && (
            <div className="w-full mb-6 p-4 bg-red-100 border border-red-400 text-red-700 rounded">
              {error}
            </div>
          )}

          <div className="w-full mb-6">
            <label 
              htmlFor="username"
              className="block font-tektur font-medium text-gray-700 mb-2"
            >
              Nombre de Usuario:
            </label>
            <input
              type="text"
              id="username"
              {...register('username')}
              disabled={isLoading}
              className={`w-full px-4 py-3 border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500 ${
                errors.username ? 'border-red-500' : 'border-gray-300'
              } ${isLoading ? 'bg-gray-100' : 'bg-white'}`}
            />
            {errors.username && (
              <p className="mt-1 text-sm text-red-600">{errors.username.message}</p>
            )}
          </div>

          <div className="w-full mb-8">
            <label 
              htmlFor="password"
              className="block font-tektur font-medium text-gray-700 mb-2"
            >
              Contraseña:
            </label>
            <input
              type="password"
              id="password"
              {...register('password')}
              disabled={isLoading}
              className={`w-full px-4 py-3 border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500 ${
                errors.password ? 'border-red-500' : 'border-gray-300'
              } ${isLoading ? 'bg-gray-100' : 'bg-white'}`}
            />
            {errors.password && (
              <p className="mt-1 text-sm text-red-600">{errors.password.message}</p>
            )}
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className={`w-full py-3 px-6 rounded-lg font-tektur font-semibold text-lg transition-colors ${
              isLoading 
                ? 'bg-gray-400 cursor-not-allowed' 
                : 'bg-primary-600 hover:bg-primary-700 text-white'
            }`}
          >
            {isLoading ? (
              <div className="flex items-center justify-center">
                <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-white"></div>
                <span className="ml-2">Cargando...</span>
              </div>
            ) : (
              'Ingresar'
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

export default Login;
